tool_calls.call:
cd /work && cat > test_lua.c << 'EOF'
#include <lua5.3/lualib.h>
#include <lua5.3/lauxlib.h>
#include <stdio.h>

int main() {
  lua_State *L = luaL_newstate();
  luaL_openlibs(L);
  int ret = luaL_dofile(L, "tests/defects4cpp.lua");
  printf("luaL_dofile returned: %d\n", ret);
  int index = lua_tonumber(L, -1);
  printf("Test index: %d\n", index);
  lua_close(L);
  return 0;
}
EOF
gcc -o test_lua test_lua.c $(pkg-config --cflags --libs lua5.3) && ./test_lua
